-- ── Odoo Community ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Odoo Community is the free, open-source core edition of the Odoo ERP platform, giving businesses self-hostable access to hundreds of interconnected business apps under the LGPL v3 license.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE($q$5,000+ employees$q$, company_size),
  headquarters = COALESCE($q$Ramillies, Belgium$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$Dutch$q$, $q$German$q$, $q$Spanish$q$]::text[],
  seo_title = COALESCE($q$Odoo Community Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Odoo Community review 2026: the free, open-source edition of Odoo's ERP suite. See what's included, self-hosting requirements, and how it compares to Enterprise.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Odoo Community is the free and open-source edition of Odoo, the modular business-management platform built by Belgian company Odoo S.A., founded in 2005 by Fabien Pinckaers (originally as TinyERP, renamed OpenERP in 2008, then Odoo in 2014) and headquartered in Ramillies, Belgium. Community is the foundation on which the entire Odoo ecosystem is built: it is released under the LGPL v3 license, meaning anyone can download, install, modify, and redistribute the source code at no cost, with no per-user fees, no artificial feature caps within its scope, and no license enforcement, provided distributed derivatives of the core code remain under the same license. It includes core apps such as Sales, CRM, Inventory, Accounting and Invoicing, Point of Sale, Project, Manufacturing, Website, and HR, all sharing one underlying database and framework so data flows between apps without manual syncing or middleware. Because it is self-hosted, businesses run Community on their own servers or cloud infrastructure and are responsible for installation, upgrades, backups, and ongoing maintenance themselves, or via one of Odoo's thousands of independent implementation partners. Community differs from Odoo Enterprise, the paid, subscription-based edition, primarily in scope and support: Enterprise adds roughly 40 additional modules and capabilities not available in Community, including Odoo Studio (drag-and-drop customization), advanced Helpdesk with SLAs, Field Service, Quality Control, Marketing Automation, Appraisals, Sign, IoT Box integration, multi-company consolidation, official mobile apps, and AI features, plus official Odoo hosting, upgrades, and support. Community's target audience is developers, system integrators, and cost-conscious businesses that want full control over their ERP stack, are comfortable self-hosting or working with a partner to do so, and don't need Enterprise-only modules. It competes less with other open-source ERPs like ERPNext or Dolibarr on raw feature count and more on ecosystem size: Odoo's app store, community, and partner network are among the largest of any open-source business-software project. Because Odoo S.A. itself is a large, well-funded company, having raised more than $500 million from investors including Sequoia Capital and CapitalG at a valuation above $5 billion, Community benefits from steady core-platform development even though the edition itself is free, funded indirectly by Enterprise and Odoo Online subscription revenue. For businesses that outgrow self-hosting or need Enterprise-only apps, Odoo provides a defined upgrade path to Enterprise without needing to migrate off the platform entirely.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e2c5c190-2aaa-46b6-b142-c38b763e334a';

