-- ── Odoo Point of Sale ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Odoo Point of Sale is a cloud-connected checkout app for retail shops and restaurants that syncs sales with real-time inventory, runs offline, and works on iPad, Android, or browser-based terminals.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (One App Free plan)$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE($q$5,000+ employees$q$, company_size),
  headquarters = COALESCE($q$Ramillies, Belgium$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$Dutch$q$, $q$German$q$, $q$Spanish$q$]::text[],
  seo_title = COALESCE($q$Odoo Point of Sale Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Odoo Point of Sale review 2026: offline-capable retail and restaurant checkout with real-time inventory sync. See features, pricing, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Odoo Point of Sale (POS) is the retail and restaurant checkout app within Odoo, the modular ERP platform built by Belgian company Odoo S.A., founded in 2005 by Fabien Pinckaers and headquartered in Ramillies, Belgium. Unlike standalone POS systems such as Square or Toast, Odoo POS runs as a connected app inside Odoo's broader ERP, meaning every sale updates inventory, accounting, and customer records in real time within the same database used by Odoo's Sales, Inventory, and Accounting apps. It can be adopted on its own for free, with unlimited users, through Odoo's One App Free plan, or as part of the paid Standard (roughly $31/user/month billed annually) and Custom (roughly $47/user/month billed annually) plans that add the rest of Odoo's app suite. The app runs on iPads, Android tablets, or any browser-based terminal, and is designed to keep working during internet outages: it processes sales offline and automatically syncs everything, transactions, inventory changes, and customer data, once connectivity returns. For retail, it supports barcode scanning with embedded pricing, weight, and loyalty data, multi-store and multi-register management, and loyalty programs or gift cards. For restaurants and cafes, it adds course-by-course order timing, kitchen and bar printer routing, table management, and split-bill support, letting staff send appetizers to the kitchen immediately while holding mains for a later fire time. Hardware such as receipt printers, barcode scanners, cash drawers, and card readers typically connect through Odoo's IoT Box, and receipts themselves can be customized to promote current offers or upcoming events. Because inventory updates in real time as sales are rung up, businesses avoid the stock discrepancies common when POS and warehouse systems run separately. Odoo POS's target audience spans independent retail stores, restaurants, cafes, and pop-up or market vendors that want checkout tightly connected to inventory and accounting without paying for and integrating three separate systems. Its main trade-off against POS specialists like Square, Toast, or Lightspeed is that achieving full hardware compatibility and advanced restaurant workflows often requires more setup and Odoo-specific hardware (the IoT Box) rather than plug-and-play consumer devices, but it wins on integration depth and total cost for businesses already using or planning to use Odoo for the rest of their operations.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '35eab88b-4ba3-4039-82ea-b4ff8bda85b1';

