-- ── Offen ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Offen is an open-source, privacy-first web analytics tool that collects usage data only with visitor consent and gives both site owners and visitors transparent access to the same data.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Small independent team$q$, company_size),
  headquarters = COALESCE($q$Berlin, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$German$q$, $q$Portuguese$q$, $q$Spanish$q$, $q$Vietnamese$q$]::text[],
  seo_title = COALESCE($q$Offen Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Offen review 2026: this open-source, privacy-first web analytics tool uses opt-in consent and end-to-end encryption. See features, self-hosting, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Offen is an open-source, self-hosted web analytics tool built around the idea of 'fair' analytics: rather than tracking visitors invisibly, it asks for explicit opt-in consent and then gives visitors the same access to their own collected data that the site operator has. It was created by German developers Frederik Ring and Hendrik Niefeld, who began building the core analytics engine in 2019, with support from the NLnet Foundation's Next Generation Internet initiative funding much of the early development. Over time the project expanded into a small suite of related tools, including the Offen Consent Tool for consent management and a proposed 'analytics.txt' standard for publicly disclosing what analytics software a site uses, all reaching maturity by summer 2024, at which point the founders formalized their work under offen.software, a Berlin-based development studio. Offen is entirely free and open source, distributed under an open license with the full codebase available on GitHub, and can be self-hosted by downloading a single compiled binary or running it as a Docker container; there is no hosted SaaS version and no paid tier. Its core differentiator versus mainstream analytics tools like Google Analytics, or even other privacy-focused alternatives like Plausible or Fathom, is its consent model: rather than collecting data by default and offering an opt-out, Offen collects nothing until a visitor actively opts in, and every visitor who does can then log in and see exactly what data has been collected about their own sessions, with all data encrypted end-to-end. It uses first-party cookies only, avoids third-party trackers or ad-network data sharing entirely, and is designed to comply readily with GDPR and similar privacy regulations by construction rather than through after-the-fact configuration. The interface and documentation are available in English, French, German, Portuguese, Spanish, and Vietnamese. Offen's target audience is privacy-conscious website owners, particularly in Europe, who want basic traffic analytics (pageviews, referrers, popular content) without compromising on consent-based, transparent data practices, as well as developers and agencies building for GDPR-sensitive clients. Its trade-off versus more feature-rich commercial or open-source analytics platforms is scope: because Offen intentionally collects only what visitors consent to share, and does not offer a managed hosting option, it suits teams comfortable running lightweight self-hosted infrastructure and who prioritize transparency over the deepest possible funnel or behavioral analytics.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '20af8fc3-9e0e-4ee6-9421-b638361573df';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = '20af8fc3-9e0e-4ee6-9421-b638361573df' AND logo IS NULL AND website IS NOT NULL;

