-- ── Officevibe ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Officevibe, now part of Workleap, is an employee engagement platform that uses pulse surveys, eNPS tracking, and anonymous feedback to help managers monitor morale and act on it.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$5/user/month (billed annually, 10-user minimum)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Approximately 400 employees (parent company Workleap)$q$, company_size),
  headquarters = COALESCE($q$Montreal, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Officevibe Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Officevibe review 2026: pulse surveys, eNPS, and anonymous feedback for employee engagement, now part of Workleap. See features, pricing, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Officevibe is an employee engagement and pulse-survey platform originally launched in 2013 by GSoft, a Montreal, Canada-based software company founded in 2006 by Simon De Baene, Guillaume Roy, and Sebastien Leduc. GSoft rebranded its entire product portfolio, including Officevibe, under the name Workleap in 2023, positioning Officevibe as its dedicated employee-engagement and feedback product within a broader talent-management suite that also includes performance management, skills, and onboarding tools. Officevibe works by sending short, recurring pulse surveys to employees, tracking metrics like employee Net Promoter Score (eNPS) over time, and collecting anonymous feedback that employees can submit without fear of it being traced back to them, giving managers a continuous read on team morale rather than relying solely on annual engagement surveys. The platform layers in 'Good Vibes,' a peer-to-peer recognition feature for celebrating wins and giving public kudos, and uses AI to generate highlights and trend summaries from survey results, suggest recommended actions for managers based on the data, and help managers draft thoughtful responses to employee feedback. Historically Officevibe sold tiered Essential and Pro plans priced between roughly $3.50 and $7.50 per employee per month depending on billing terms, but Workleap simplified this in 2024 into a single unified plan priced at $5 per user per month billed annually (or $6.25 per user per month billed monthly), with a 10-user minimum. Officevibe integrates with common workplace tools including Slack, Microsoft Teams, and various HRIS platforms for automatic employee provisioning. Its target audience is small and mid-sized businesses, roughly 10 to 200 employees, where a lightweight, easy-to-deploy engagement tool that a single HR or people-ops person can manage is more valuable than a heavyweight enterprise HR suite. Compared to broader HR platforms like Culture Amp, Lattice, or 15Five, Officevibe differentiates on simplicity and speed of setup rather than depth of performance-management or compensation features, which live in Workleap's separate, higher-priced platform tiers (Standard at $4,999/year and Pro at $11,999/year) for organizations wanting a fuller HR suite. Workleap, the parent company, is headquartered in Montreal and reports over 70,000 people leaders using its products globally, with roughly 400 employees of its own.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a31391fe-79aa-479e-ad05-f7def34d36ee';

