-- ── Oh Dear ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Oh Dear is an all-in-one website monitoring tool, built by two Belgian developers, that tracks uptime, SSL certificates, performance, broken links, DNS, and scheduled tasks from a single dashboard.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$€15/month (Solo plan)$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Small team (under 10 people)$q$, company_size),
  headquarters = COALESCE($q$Belgium$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Oh Dear Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Oh Dear review 2026: uptime, SSL, performance, and cron monitoring in one dashboard, built by two Belgian developers. See pricing plans and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Oh Dear is an all-in-one website and server monitoring tool founded in 2018 by Freek Van der Herten, a Belgian agency owner and prolific open-source PHP and Laravel developer, and Mattias Geniar, a sysadmin and team lead at the Belgian hosting company Nucleus. The pairing was deliberate: Van der Herten focused on the developer- and application-facing side of monitoring, while Geniar brought infrastructure, DNS, and security expertise, and their stated goal was to build a tool that covers 'the whole site, not just the half you think about,' combining checks that developers and operations teams traditionally split across separate tools. Rather than offering just uptime pings, Oh Dear bundles uptime monitoring, SSL certificate expiration tracking, broken-link checking, performance and Lighthouse-based audits, DNS record and domain-expiration monitoring, scheduled task (cron) monitoring, ping and TCP port checks, application health checks, and public status pages into one product, and every plan includes every feature; the only thing that changes between pricing tiers is how many sites or servers are covered. Pricing starts at €15 per month for the Solo plan (2 sites) and scales through Freelance (€49/month, 10 sites), Studio (€99/month, 25 sites), Agency (€149/month, 50 sites), Agency Plus (€199/month, 75 sites), Portfolio (€249/month, 100 sites), Portfolio Plus (€329/month, 150 sites), and Scale (€399/month, 200 sites), with custom Enterprise pricing above that; annual billing gets two months free, and there's a 10-day free trial with no credit card required. Since the company began in the Laravel and PHP developer community, where both founders are well known, Oh Dear has built strong brand trust among freelance developers and small agencies monitoring client sites, positioning it as a European, developer-friendly alternative to tools like Pingdom, UptimeRobot, or StatusCake, which often gate features like SSL monitoring or status pages behind higher tiers. Its target audience is freelance developers, digital agencies, and small-to-mid-size SaaS companies that want a single dashboard covering uptime, performance, and infrastructure health for a portfolio of client or product sites, rather than piecing together several point-solution monitoring tools. Being a small, founder-led company rather than a venture-backed startup, Oh Dear has grown its feature set steadily since 2018 through direct founder involvement and continues to add capabilities like AI-powered checks and DNS blocklist monitoring.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7f675195-8d9d-4857-a42d-0da0b4ca4707';

