INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Remote print monitoring and control$q$, $q$Start, pause, cancel, and track 3D print jobs from any browser on your network, with live GCODE visualization and temperature graphs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Webcam streaming and timelapses$q$, $q$Watch prints live via webcam and automatically generate timelapse videos of completed jobs.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Extensive plugin ecosystem$q$, $q$Install thousands of community-built plugins directly from OctoPrint's official plugin repository to add features like bed-leveling visualization, advanced timelapses, and UI themes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Printer-agnostic support$q$, $q$Works with most consumer FDM 3D printers over USB, with community profiles and plugins covering printer-specific quirks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Access control and multi-user permissions$q$, $q$Restrict who can view or control the printer with built-in user accounts and permission levels.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$REST API$q$, $q$A full REST API lets developers integrate OctoPrint with external dashboards, farm-management tools, and automation scripts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Self-hosted and private$q$, $q$Runs entirely on hardware you control, such as a Raspberry Pi, with no required cloud account or third-party data sharing.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Completely free and open source with no paid tiers or feature limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Massive plugin ecosystem covering nearly every common 3D-printing workflow need$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Large, active community and extensive documentation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Works with almost any consumer 3D printer over USB$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Full data privacy since everything runs on hardware you control$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Requires separate hardware, typically a Raspberry Pi, to run continuously$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$No official hosted or cloud version, so remote-over-internet access requires extra setup$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Initial setup and plugin management can be technical for non-technical makers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Development pace depends on volunteer contributions and Patreon donations rather than a dedicated company roadmap$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Managing large print farms requires pairing OctoPrint with additional tools like OctoFarm$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Is OctoPrint free to use?$q$, $q$Yes. OctoPrint is free and open-source software released under the AGPL license, with no paid tiers, subscriptions, or feature restrictions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Do I need a Raspberry Pi to run OctoPrint?$q$, $q$A Raspberry Pi running the official OctoPi image is the most common setup, but OctoPrint can also run on any Linux, Windows, or macOS computer connected to your printer.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Can OctoPrint control any 3D printer?$q$, $q$OctoPrint works with most consumer FDM printers that connect over USB and speak standard GCODE-based firmware, and the community maintains profiles and plugins for many specific printer models.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$How do I install OctoPrint plugins?$q$, $q$Plugins can be browsed and installed directly from the built-in Plugin Manager inside OctoPrint's web interface, without needing command-line access.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Is it safe to expose OctoPrint to the internet?$q$, $q$OctoPrint recommends against directly exposing it to the internet without additional protections such as a reverse proxy, VPN, or a dedicated remote-access service, since misconfigured public access has led to reported printer misuse.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Who maintains OctoPrint?$q$, $q$OctoPrint is maintained primarily by its creator, Gina Haussge, with contributions from an active open-source community, and funded largely through Patreon donations.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$What is the difference between OctoPrint and OctoFarm?$q$, $q$OctoPrint manages a single printer's interface, while OctoFarm is a separate open-source tool that provides a dashboard for monitoring multiple OctoPrint instances at once, useful for print farms.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Hobbyist remote printer monitoring$q$, $q$Makers run OctoPrint on a Raspberry Pi next to their printer so they can check progress, watch the webcam feed, and start new jobs from their phone or laptop without being in the same room.$q$, $q$3D-printing hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Classroom and makerspace print management$q$, $q$Schools and makerspaces use OctoPrint's access controls and web dashboard to let multiple students or members queue and monitor prints on shared printers safely.$q$, $q$Educators and makerspace operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$Small print farm operations$q$, $q$Small businesses running several printers pair OctoPrint on each unit with a farm-management layer like OctoFarm to track jobs, failures, and completion across all machines from one screen.$q$, $q$Small 3D-printing businesses and print-on-demand shops$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$OctoPrint (Self-Hosted)$q$, $q$Free$q$, $q$N/A - one-time setup$q$, NULL, $q$["Unlimited use, no seat or feature limits","Full plugin repository access","Self-hosted on your own hardware (e.g. Raspberry Pi)","Community support via forums and GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OctoPrint turns a bare 3D printer into a networked device you can watch and operate from anywhere on your local network or, with additional configuration, remotely over the internet. Instead of standing next to a noisy printer or leaving a laptop tethered to it for hours, users install OctoPrint on a small always-on computer, most commonly a Raspberry Pi running the official OctoPi image, and connect it to the printer over USB.$q$, $q$The project began as a personal side project by Gina Haussge in December 2012 and grew into what is now considered the standard open-source web interface for desktop 3D printing, with an active GitHub community, an official plugin repository, and support baked into many commercial printer firmwares and slicers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, OctoPrint provides a live dashboard showing print progress, GCODE visualization, temperature graphs, and full control over printer movement, extrusion, and print jobs (start, pause, cancel). A built-in webcam integration lets users watch prints live and automatically stitch timelapse videos of completed jobs.$q$, $q$The plugin system is what sets OctoPrint apart: thousands of community plugins extend it with features like bed-mesh visualization, advanced timelapse control (Octolapse), custom UI themes, notification integrations, and printer-specific tooling, all installable from an in-app plugin manager without touching the command line.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('33fedead-cbf1-426b-aefe-c1f89bb34b01', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OctoPrint itself is completely free and always will be, since it is released under the AGPL open-source license; there is no paid tier, seat limit, or feature gate. Running it does require your own hardware (typically a Raspberry Pi, which costs roughly $35-$80) and, optionally, a webcam.$q$, $q$Because there is no company behind OctoPrint selling licenses, ongoing development is funded through voluntary donations, primarily via Patreon, where thousands of backers collectively support Gina Haussge's full-time work on the project.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$AI-powered invoice data capture$q$, $q$Automatically extracts and pre-fills data from scanned or emailed vendor bills, reducing manual entry.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Automated bank reconciliation$q$, $q$Connects to over 28,000 banks worldwide and uses AI matching to reconcile transactions against invoices and bills automatically.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Multi-country tax engine$q$, $q$Supports price-included and price-excluded tax, tax-on-tax, partial exemptions, and localized tax reports for accrual or cash accounting.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Real-time financial reporting$q$, $q$Profit and loss, balance sheet, cash flow, and custom dashboards update instantly as transactions post across Odoo.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Budgeting and asset management$q$, $q$Track budgets against actuals and manage fixed-asset depreciation schedules from within the same app.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Multi-currency and multi-company accounting$q$, $q$Consolidate accounts across multiple currencies and legal entities from a single Odoo database.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Native integration with Sales, Inventory, and POS$q$, $q$Invoices, bills, and payments generated elsewhere in Odoo post directly to the ledger without manual syncing.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Deep native integration with Sales, Inventory, CRM, and POS avoids duplicate data entry$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$AI-powered invoice capture and bank reconciliation cut manual bookkeeping work$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Free to start for unlimited users via the One App Free plan$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Localized tax and reporting support for 100+ countries$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Scales into a full ERP as the business grows, without switching platforms$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Full value requires adopting other Odoo apps rather than using Accounting as a pure standalone tool$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Per-user pricing on the Standard and Custom plans can add up for larger teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Migrating historical data from QuickBooks, Xero, or similar tools takes upfront effort$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Some advanced compliance and localization features depend on Odoo Enterprise or country-specific packs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Support quality and implementation depth often depend on the Odoo partner handling setup$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Is Odoo Accounting free?$q$, $q$Yes, Odoo Accounting can be used for free with unlimited users through Odoo's One App Free plan; the paid Standard and Custom plans unlock the full suite of Odoo apps alongside it.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Can Odoo Accounting replace QuickBooks or Xero?$q$, $q$For businesses already using or planning to use other Odoo apps like Sales, Inventory, or CRM, Odoo Accounting can fully replace standalone tools like QuickBooks or Xero, since it shares one database with the rest of the ERP.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Does Odoo Accounting support multiple currencies?$q$, $q$Yes, it supports multi-currency accounting as well as multi-company consolidation for businesses operating across several legal entities.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$How accurate is Odoo's AI invoice capture?$q$, $q$Odoo states its AI-powered invoice recognition correctly captures data from around 98% of scanned or emailed vendor bills, reducing manual entry.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Does Odoo Accounting handle tax compliance for my country?$q$, $q$Odoo maintains localized tax and accounting rules for more than 100 countries, with tax reports formatted for local regulatory requirements.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$How does bank reconciliation work in Odoo?$q$, $q$Odoo connects directly to over 28,000 banks and uses AI-powered matching to suggest or automatically complete reconciliation between bank statements and recorded invoices or bills.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Who is Odoo Accounting best suited for?$q$, $q$It suits small and mid-sized businesses that want accounting tightly integrated with sales, inventory, and other operations, as well as accounting firms managing multiple client entities.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$All-in-one bookkeeping for small businesses$q$, $q$Small businesses use Odoo Accounting to handle invoicing, expenses, and bank reconciliation without paying for a separate accounting subscription.$q$, $q$Small business owners and bookkeepers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Integrated finance for growing companies$q$, $q$Scaling companies connect Accounting to Odoo Sales, Inventory, and CRM so revenue, stock, and cash flow stay in sync automatically as order volume grows.$q$, $q$Finance teams at growing SMBs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Multi-entity accounting for firms and franchises$q$, $q$Accounting firms and multi-location businesses use Odoo's multi-company features to consolidate books across several legal entities from one system.$q$, $q$Accounting firms and multi-location businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$One App Free$q$, $q$Free$q$, $q$Forever$q$, NULL, $q$["Unlimited users on the Accounting app","Hosting, maintenance, and upgrades included","Access to any apps Accounting depends on at no cost"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Standard$q$, $q$$31.10/user/month (billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Full suite of Odoo apps including Accounting","Odoo Online hosting","Unlimited support, hosting, and maintenance"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$Custom$q$, $q$$46.80/user/month (billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Standard","Odoo Studio customization","Multi-company support and external API access","Choice of Odoo Online, Odoo.sh, or on-premise hosting"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Odoo Accounting handles invoicing, bill payment, bank reconciliation, and financial reporting as a native module of the Odoo ERP platform, meaning transactions created in Sales, Inventory, or Point of Sale post directly to the books without manual re-entry.$q$, $q$It is built for businesses that want accounting to sit inside the same system as the rest of their operations rather than as a disconnected tool that requires constant syncing or double data entry.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$AI-assisted invoice capture reads scanned or emailed vendor bills and pre-fills the relevant fields, while bank reconciliation connects directly to thousands of banks and suggests matches automatically, cutting down the manual work typically associated with month-end closing.$q$, $q$The built-in tax engine handles country-specific tax rules, and real-time financial reports (profit and loss, balance sheet, cash flow, and custom dashboards) update instantly as transactions are recorded elsewhere in Odoo.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5b7732f8-9233-468e-8b6e-92b089440d94', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Odoo Accounting can be used entirely free, for unlimited users, through Odoo's One App Free plan, which includes hosting and maintenance for that single app. Businesses that also want Sales, Inventory, CRM, or other Odoo apps move to the Standard plan (around $31 per user per month billed annually) or the Custom plan (around $47 per user per month billed annually), which adds Odoo Studio customization, multi-company support, and API access.$q$, $q$Because pricing is per named user across whichever apps are enabled, cost scales with team size rather than transaction volume or invoice count.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$LGPL v3 open-source license$q$, $q$Full source code access with the freedom to use, modify, and redistribute it, with no per-user or per-app licensing fees.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Modular app architecture$q$, $q$Install only the apps you need, such as Sales, Inventory, Accounting, or CRM, all sharing one underlying database.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Self-hosting freedom$q$, $q$Deploy on your own servers or any cloud provider, giving full control over data location, backups, and infrastructure.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Large community app store$q$, $q$Thousands of community-built modules extend Community beyond the core apps, covering industry-specific and niche needs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Developer and API extensibility$q$, $q$Full access to Odoo's Python-based framework and APIs for custom development and integrations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Active open-source community$q$, $q$Public GitHub repositories, forums, and a large partner network provide support outside of official Odoo channels.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Clear upgrade path to Enterprise$q$, $q$Businesses that outgrow Community's scope can move to Odoo Enterprise without abandoning their existing data or setup.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$No license fees or per-user costs, ever$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Full source code access with freedom to modify and self-host$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Large, mature ecosystem of apps, partners, and documentation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Modular design lets you run only the apps your business needs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$No vendor lock-in since the code and data stay under your control$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Lacks Enterprise-only modules like Studio, Field Service, and advanced Helpdesk$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Self-hosting requires technical resources for setup, security, and upgrades$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$No official Odoo support or SLA is included, only community or partner support$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Major version upgrades can require manual data migration work$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$No official mobile app or IoT Box integration available in this edition$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Is Odoo Community really free?$q$, $q$Yes, Odoo Community is released under the LGPL v3 open-source license and can be downloaded, self-hosted, and used with no license fees, though hosting and implementation still cost time or money.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$What's the difference between Odoo Community and Odoo Enterprise?$q$, $q$Enterprise adds roughly 40 extra modules and features not in Community, such as Odoo Studio, advanced Helpdesk, Field Service, multi-company consolidation, and official mobile apps, plus official hosting, upgrades, and support.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Can I self-host Odoo Community?$q$, $q$Yes, Community is designed to be self-hosted on your own servers or any cloud provider; Odoo also has an on-premise installation guide and a large partner network that can host or manage it for you.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Can I upgrade from Community to Enterprise later?$q$, $q$Yes, Odoo provides a defined migration path from Community to Enterprise for businesses that need Enterprise-only apps or official support as they grow.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$What apps are included in Odoo Community?$q$, $q$Community includes core versions of apps like Sales, CRM, Inventory, Accounting and Invoicing, Point of Sale, Project, Manufacturing, Website, and HR, among others.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Is Odoo Community good for small businesses?$q$, $q$It's a strong fit for small businesses with in-house technical resources or an implementation partner, since it offers a full ERP at no license cost, though very small teams without IT support may prefer the hosted Standard plan instead.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$What does the LGPL v3 license actually require?$q$, $q$LGPL v3 lets you use, modify, and distribute Odoo Community freely, and any distributed derivative of the core Community code must remain under the same license, though this does not extend to separate Enterprise-only modules.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Budget-conscious ERP for technical teams$q$, $q$Businesses with in-house developers self-host Odoo Community to run a full ERP without paying per-user license fees.$q$, $q$Startups and SMBs with technical staff$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Custom ERP builds by system integrators$q$, $q$Odoo partners and system integrators use Community's open codebase as a foundation for heavily customized, industry-specific ERP deployments.$q$, $q$Odoo implementation partners and developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Proof-of-concept before committing to Enterprise$q$, $q$Companies evaluate Odoo by self-hosting Community first, testing workflows before deciding whether to move to the paid Enterprise edition for official support and extra modules.$q$, $q$Businesses evaluating ERP platforms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Community Edition (Self-Hosted)$q$, $q$Free$q$, $q$N/A - open source$q$, NULL, $q$["Full source code under LGPL v3","Core apps including Sales, CRM, Inventory, Accounting, and POS","Self-hosted on your own infrastructure","Community and partner support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Enterprise Standard (upgrade path)$q$, $q$$31.10/user/month (billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Full Odoo Enterprise app suite","Official Odoo Online hosting","Official support, hosting, and maintenance"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$Enterprise Custom (upgrade path)$q$, $q$$46.80/user/month (billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Enterprise Standard","Odoo Studio, multi-company support, API access","Odoo Online, Odoo.sh, or on-premise hosting options"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Odoo Community is the open-source core of the Odoo platform: the same underlying framework and database model used across every Odoo app, released under the LGPL v3 license so anyone can self-host it for free.$q$, $q$It includes core versions of Odoo's most-used apps, letting businesses run a full, interconnected ERP, covering sales, inventory, accounting, and more, without paying license fees, though hosting and implementation still require time or budget.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Because Community shares Odoo's single-database architecture, installing multiple apps (say, CRM and Inventory) automatically links their data, so a won opportunity can trigger a delivery order without custom integration work.$q$, $q$The LGPL v3 license permits modification and redistribution, which has produced a large ecosystem of community-built apps in the Odoo Apps store, alongside official documentation and an active developer community on GitHub and Odoo's forums.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e2c5c190-2aaa-46b6-b142-c38b763e334a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Odoo Community itself carries no license fee, no per-user cost, and no expiration; the only ongoing costs are hosting infrastructure, implementation, and any development or maintenance work, whether done in-house or through an Odoo partner.$q$, $q$Businesses that want Odoo's official hosting, automatic upgrades, and Enterprise-only modules can move to the paid Standard plan (around $31/user/month billed annually) or Custom plan (around $47/user/month billed annually), which run the Enterprise edition instead of Community.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Visual Kanban pipeline$q$, $q$Drag-and-drop opportunities through customizable stages with win probability and time-in-stage tracked automatically.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Predictive lead scoring$q$, $q$A machine-learning model trained on historical CRM data estimates each lead's likelihood of closing to help prioritize follow-up.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Automated lead capture$q$, $q$Captures leads from website forms, email aliases, live chat conversations, and trade-show CSV imports.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Sales forecasting$q$, $q$Pipeline value rolls up automatically by expected close date and stage probability for revenue forecasting.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Activity tracking$q$, $q$Logs every call, email, and meeting against a contact or opportunity to build a complete interaction history.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$One-click quote-to-cash$q$, $q$Converts opportunities into quotes, then sales orders, stock reservations, and invoices without leaving the record.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Lead assignment rules$q$, $q$Automatically route leads to reps based on score, territory, or round-robin logic.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Closed deals can automatically trigger quotes, orders, and invoices without re-entering data$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Predictive lead scoring is built in at no extra cost$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Free entry point for small sales teams via the One App Free plan$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Highly customizable pipeline stages and views$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Scales naturally into a full ERP as a business adopts more Odoo apps$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Marketing automation depth trails CRM-specialist platforms like HubSpot$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Third-party app marketplace and integrations are less extensive than Salesforce's ecosystem$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Mobile CRM experience is less polished than dedicated mobile-first CRMs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Initial pipeline and automation setup takes configuration time$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Full benefits require adopting other Odoo apps rather than using CRM in isolation$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Is Odoo CRM free?$q$, $q$Yes, Odoo CRM can be used for free with unlimited users through Odoo's One App Free plan; the paid Standard and Custom plans add the rest of Odoo's apps alongside it.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Does Odoo CRM include lead scoring?$q$, $q$Yes, it includes predictive lead scoring, a machine-learning model trained on historical CRM data that estimates each lead's probability of converting.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Can Odoo CRM automatically create invoices from closed deals?$q$, $q$Yes, because CRM shares a database with Odoo's Sales and Accounting apps, a won opportunity can trigger a quote, sales order, and invoice automatically.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$How does Odoo CRM capture leads?$q$, $q$Leads are captured automatically from website forms, dedicated email aliases, live chat conversations, and CSV imports from events or trade shows.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Is Odoo CRM good for small sales teams?$q$, $q$Yes, small teams can start on the free One App Free plan, though the value grows as a business connects CRM to other Odoo apps like Sales and Marketing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$How does Odoo CRM compare to Salesforce or HubSpot?$q$, $q$Odoo CRM offers less marketing-automation and app-marketplace depth than CRM specialists like Salesforce or HubSpot, but provides tighter native integration with quoting, invoicing, and inventory at a lower total cost.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Can I customize the sales pipeline stages?$q$, $q$Yes, pipeline stages, fields, and views are fully customizable to match a team's specific sales process.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Pipeline management for small sales teams$q$, $q$Sales reps track opportunities through a visual pipeline, log activities, and get automated forecasts without needing a separate CRM subscription.$q$, $q$Small business sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Quote-to-cash automation$q$, $q$Sales teams already using Odoo Sales and Accounting close deals in CRM that automatically generate quotes, orders, and invoices.$q$, $q$Sales teams using multiple Odoo apps$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Multi-pipeline agency and franchise management$q$, $q$Agencies and franchise networks manage separate pipelines per client or location while keeping reporting centralized in one Odoo database.$q$, $q$Agencies and multi-location businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$One App Free$q$, $q$Free$q$, $q$Forever$q$, NULL, $q$["Unlimited users on the CRM app","Hosting, maintenance, and upgrades included","Access to any apps CRM depends on at no cost"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Standard$q$, $q$$31.10/user/month (billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Full suite of Odoo apps including CRM","Odoo Online hosting","Unlimited support, hosting, and maintenance"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Custom$q$, $q$$46.80/user/month (billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Standard","Odoo Studio customization","Multi-company support and external API access","Choice of Odoo Online, Odoo.sh, or on-premise hosting"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Odoo CRM organizes a sales team's pipeline into a visual, drag-and-drop Kanban board where opportunities move through configurable stages from first contact to closed-won, with win probability and time-in-stage tracked automatically.$q$, $q$Because it's built on the same database as the rest of Odoo, a closed deal in Odoo CRM can trigger a quote, sales order, and invoice automatically, connecting sales activity directly to fulfillment and accounting without manual handoffs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Predictive lead scoring uses a machine-learning model trained on historical CRM data to estimate each lead's probability of closing, which teams can use to prioritize follow-up or drive automated lead-assignment rules by score, territory, or round robin.$q$, $q$Leads are captured automatically from website forms, email aliases, live chat, and trade-show imports, while every call, email, and meeting logged against a contact builds a full activity timeline that supports pipeline and win-loss reporting.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Odoo CRM can be used for free with unlimited users through the One App Free plan. Businesses that also want Odoo's Sales, Marketing, or Accounting apps move to the Standard plan (around $31/user/month billed annually) or Custom plan (around $47/user/month billed annually).$q$, $q$Pricing is per named user across whichever Odoo apps are active, so a sales team using only CRM pays nothing beyond the free tier, while teams adopting the full suite pay per seat for the whole bundle.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Real-time inventory sync$q$, $q$Every sale immediately updates stock levels across the connected Odoo Inventory app, across single or multiple store locations.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Offline mode with auto-sync$q$, $q$Continues processing sales and inventory changes without an internet connection, syncing automatically once reconnected.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Restaurant course and kitchen routing$q$, $q$Sends order items to kitchen or bar printers at different times per course, with table management and bill splitting.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Barcode scanning with embedded data$q$, $q$Scans barcodes that embed price, weight, or loyalty information for fast, accurate checkout.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Multi-store and multi-register management$q$, $q$Runs multiple registers and locations from a single Odoo database with centralized reporting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Loyalty programs and gift cards$q$, $q$Built-in tools to run point-based loyalty programs and issue or redeem gift cards at checkout.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$IoT Box hardware support$q$, $q$Connects receipt printers, scales, cash drawers, and card readers over the local network via Odoo's IoT Box.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Real-time inventory sync eliminates stock discrepancies between POS and warehouse$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Works offline and syncs automatically, useful for unreliable internet connections$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Free entry point with unlimited users via the One App Free plan$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Handles both retail and restaurant workflows in one system$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Runs on affordable, widely available hardware like iPads and Android tablets$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Full hardware compatibility (printers, cash drawers, card readers) often requires Odoo's IoT Box$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Advanced restaurant features like course firing and table maps require initial configuration$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Per-user costs on Standard and Custom plans can add up for businesses with many registers or staff$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Some niche retail features, like complex tiered loyalty programs, may need Enterprise-only apps$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Initial setup requires familiarity with the Odoo platform rather than being fully plug-and-play$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Is Odoo Point of Sale free?$q$, $q$Yes, it can be used for free with unlimited users through Odoo's One App Free plan; adding other Odoo apps requires the paid Standard or Custom plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Does Odoo POS work without internet?$q$, $q$Yes, it's designed to keep processing sales, inventory changes, and customer data offline, then automatically syncs everything once the connection returns.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$What hardware does Odoo POS support?$q$, $q$It supports iPads, Android tablets, and browser-based terminals, with receipt printers, scales, cash drawers, and card readers typically connected through Odoo's IoT Box.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Can Odoo POS handle restaurants as well as retail?$q$, $q$Yes, it includes restaurant-specific tools like course-by-course kitchen and bar printer routing, table management, and bill splitting, alongside retail tools like barcode scanning and multi-store inventory.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Does Odoo POS update inventory automatically?$q$, $q$Yes, every sale updates stock levels in real time across the connected Odoo Inventory app, whether for a single store or multiple locations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Does Odoo POS support loyalty programs and gift cards?$q$, $q$Yes, it includes built-in point-based loyalty programs and gift card issuance and redemption at checkout.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$How does Odoo POS compare to Square or Toast?$q$, $q$Odoo POS offers deeper native integration with inventory and accounting for businesses already on Odoo, while Square and Toast offer more plug-and-play hardware and payment processing specifically tuned for retail or restaurants respectively.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Independent retail store checkout$q$, $q$Small retail shops use Odoo POS to ring up sales on iPads while inventory updates automatically in the back office.$q$, $q$Independent retailers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Restaurant and cafe order management$q$, $q$Restaurants use course-by-course kitchen routing and table management to coordinate front-of-house and kitchen staff during service.$q$, $q$Restaurants and cafes$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Pop-up shops and market vendors$q$, $q$Vendors at markets or pop-up events use Odoo POS's offline mode to keep selling without reliable internet, syncing sales once back online.$q$, $q$Pop-up and market vendors$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$One App Free$q$, $q$Free$q$, $q$Forever$q$, NULL, $q$["Unlimited users on the Point of Sale app","Hosting, maintenance, and upgrades included","Access to any apps POS depends on at no cost"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Standard$q$, $q$$31.10/user/month (billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Full suite of Odoo apps including Point of Sale","Odoo Online hosting","Unlimited support, hosting, and maintenance"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$Custom$q$, $q$$46.80/user/month (billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Standard","Odoo Studio customization","Multi-company support and external API access","Choice of Odoo Online, Odoo.sh, or on-premise hosting"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Odoo Point of Sale is a checkout system built to run on tablets, browsers, or dedicated terminals in retail stores and restaurants, designed from the ground up to share live data with the rest of the Odoo ERP rather than operating as an isolated till.$q$, $q$Every transaction rung up in Odoo POS updates inventory counts, customer records, and accounting entries in real time, so store, warehouse, and finance teams are always looking at the same numbers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The app is built to keep working when the internet drops: sales, inventory adjustments, and customer updates continue offline and sync automatically once the connection is restored, which matters for retail floors and busy restaurant services where downtime isn't an option.$q$, $q$Restaurant-specific tools let staff fire courses to the kitchen or bar at different times, manage table layouts, and split bills, while retail-specific tools handle barcode scanning with embedded pricing and loyalty data, multi-store inventory, and gift cards.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Odoo POS can be used for free with unlimited users on the One App Free plan. Adding Odoo's Inventory, Accounting, or other apps moves a business to the Standard plan (around $31/user/month billed annually) or Custom plan (around $47/user/month billed annually).$q$, $q$Hardware, such as receipt printers, barcode scanners, and card readers, is a separate cost from the software subscription and typically connects through Odoo's IoT Box for full compatibility.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Opt-in-only data collection$q$, $q$No usage data is collected until a visitor actively consents, unlike default-on tracking used by most analytics tools.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Visitor-facing data access$q$, $q$Visitors who opt in can log in and see exactly what data has been collected about their own sessions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$End-to-end encrypted storage$q$, $q$All collected analytics data is encrypted end-to-end rather than stored in plain, queryable form.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$First-party cookies only$q$, $q$No third-party trackers or cross-site cookies, reducing exposure to ad-network data sharing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Self-hosted deployment$q$, $q$Runs as a single binary or Docker container on infrastructure you control, with no required third-party hosting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$GDPR-oriented design$q$, $q$Consent-first collection and data minimization are built into the architecture rather than bolted on afterward.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Multi-language support$q$, $q$Available in English, French, German, Portuguese, Spanish, and Vietnamese.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Completely free and open source with no paid tier$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Consent-first model is genuinely privacy-respecting rather than opt-out-based$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Visitors get transparent access to their own collected data$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$End-to-end encryption of stored analytics data$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Lightweight and simple to self-host via Docker or a single binary$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$No hosted SaaS option, so self-hosting infrastructure is required$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Opt-in-only consent naturally reduces the volume of data collected compared to opt-out tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Smaller community and plugin ecosystem than Google Analytics or Plausible$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Fewer built-in integrations with marketing and ad platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Development pace depends on a small founding team and grant funding rather than a commercial roadmap$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Is Offen free to use?$q$, $q$Yes, Offen is fully open source and free, distributed for self-hosting with no paid tier or hosted SaaS option.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$How is Offen different from Google Analytics?$q$, $q$Offen only collects data from visitors who actively opt in, encrypts stored data end-to-end, and lets visitors see their own collected data, whereas Google Analytics tracks by default and doesn't expose raw visitor-level data back to users.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Who built Offen?$q$, $q$Offen was created by German developers Frederik Ring and Hendrik Niefeld, who started the project in 2019 and now maintain it under their Berlin-based studio, offen.software.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$How do I install Offen?$q$, $q$Offen can be deployed by downloading a single compiled binary or running the official Docker image on your own server or cloud infrastructure.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Is Offen GDPR compliant?$q$, $q$Offen is designed around opt-in consent, data minimization, and first-party-only cookies, which aligns closely with GDPR principles, though compliance also depends on how it's configured and disclosed on your site.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$What languages does Offen support?$q$, $q$The interface is available in English, French, German, Portuguese, Spanish, and Vietnamese.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Does Offen offer a hosted version?$q$, $q$No, Offen is self-hosted only; there is no official managed hosting or SaaS plan.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Privacy-first analytics for EU websites$q$, $q$European businesses use Offen to get basic traffic insights while meeting GDPR consent requirements by design.$q$, $q$EU-based website owners and agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Transparent analytics for privacy-focused products$q$, $q$Privacy-conscious startups and open-source projects adopt Offen to align their analytics practices with their broader privacy commitments.$q$, $q$Privacy-focused startups and open-source maintainers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Self-hosted analytics for data-sovereignty needs$q$, $q$Organizations that must keep analytics data on infrastructure they control, such as those in regulated industries, self-host Offen instead of using third-party cloud analytics.$q$, $q$Organizations with data-residency requirements$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$Offen (Self-Hosted)$q$, $q$Free$q$, $q$N/A - open source$q$, NULL, $q$["Unlimited use, self-hosted","Opt-in consent-based data collection","End-to-end encrypted data storage","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Offen is a self-hosted, open-source alternative to Google Analytics built around explicit visitor consent: instead of tracking everyone by default, it only records data from visitors who actively opt in, and those visitors can then view exactly what was collected about them.$q$, $q$The project was started in 2019 by German developers Frederik Ring and Hendrik Niefeld and has since grown into a small suite of related privacy tools, including a standalone consent manager, all released as open source and maintained under their studio, offen.software, based in Berlin.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Offen tracks pageviews, referrers, and basic usage metrics using first-party cookies only, with all stored data encrypted end-to-end and no data shared with third parties or ad networks.$q$, $q$Because it's self-hosted, site owners deploy it via a single downloadable binary or a Docker image on their own infrastructure, giving full control over where data lives, which matters for teams with strict data-residency or GDPR requirements.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('20af8fc3-9e0e-4ee6-9421-b638361573df', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Offen is completely free with no paid tier, since it is open-source software distributed for self-hosting rather than sold as a hosted service. Costs are limited to whatever server infrastructure you choose to run it on.$q$, $q$Ongoing development has been supported through grants, notably from the NLnet Foundation, rather than subscription revenue, which keeps the tool free but means release pace depends on the small founding team's capacity and funding.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Recurring pulse surveys$q$, $q$Short, automated surveys sent on a regular cadence to track engagement trends over time rather than once a year.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Employee Net Promoter Score (eNPS) tracking$q$, $q$Continuously measures eNPS so managers can see engagement trends rise or fall in near real time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Anonymous feedback channel$q$, $q$Employees can submit feedback anonymously at any time, encouraging candor without fear of attribution.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Good Vibes peer recognition$q$, $q$Lets team members send public recognition cards to celebrate wins and build appreciation culture.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$AI-powered survey reporting$q$, $q$Automatically generates highlights, trend summaries, and recommended actions from survey results.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Feedback reply assistance$q$, $q$AI helps managers draft thoughtful, constructive responses to employee feedback.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$HRIS and workplace integrations$q$, $q$Connects with Slack, Microsoft Teams, and HRIS platforms for automatic employee provisioning and notifications.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Simple, transparent pricing at $5/user/month with no tiered feature gating$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Continuous pulse surveys give a more current read on morale than annual surveys$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Anonymous feedback channel encourages honest input$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$AI-generated highlights reduce the manual work of interpreting survey data$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Easy for a single HR or people-ops person to deploy and manage$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$10-user minimum means very small teams pay for seats they may not need$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Less depth in performance management and compensation than Workleap's higher-tier HR platform$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Limited standalone use outside of the Workleap ecosystem for broader HR needs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Fewer advanced customization options than dedicated enterprise engagement platforms like Culture Amp$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Historical pricing changes from tiered to unified may require re-budgeting for long-time customers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$What is Officevibe used for?$q$, $q$Officevibe is an employee engagement platform that uses recurring pulse surveys, eNPS tracking, and anonymous feedback to help managers monitor and improve team morale.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Is Officevibe part of Workleap?$q$, $q$Yes, Officevibe was originally built by GSoft, a Montreal software company founded in 2006, which rebranded as Workleap in 2023; Officevibe remains a core Workleap product.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$How much does Officevibe cost?$q$, $q$Officevibe is priced at $5 per user per month billed annually, or $6.25 per user per month billed monthly, with a 10-user minimum.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Is Officevibe feedback really anonymous?$q$, $q$Yes, employees can submit feedback anonymously, and Officevibe is designed so responses can't be traced back to individual employees.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Does Officevibe integrate with Slack or Microsoft Teams?$q$, $q$Yes, Officevibe integrates with Slack, Microsoft Teams, and various HRIS platforms for survey distribution and employee provisioning.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$What size company is Officevibe best for?$q$, $q$Officevibe is best suited to small and mid-sized businesses, roughly 10 to 200 employees, that want a lightweight, easy-to-manage engagement tool.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$How is Officevibe different from Culture Amp or Lattice?$q$, $q$Officevibe focuses specifically on lightweight, continuous engagement surveys and recognition, while platforms like Culture Amp or Lattice offer deeper performance-management and compensation features, often at a higher price point.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Continuous engagement monitoring$q$, $q$HR teams use recurring pulse surveys and eNPS tracking to catch morale issues early instead of waiting for an annual survey.$q$, $q$HR and people-ops teams at SMBs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Manager coaching with AI-generated insights$q$, $q$People managers use AI-generated highlights and recommended actions to know what to address after each survey cycle without manually analyzing raw data.$q$, $q$People managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Peer recognition culture building$q$, $q$Teams use Good Vibes recognition cards to reinforce a culture of appreciation alongside formal engagement measurement.$q$, $q$Distributed and hybrid teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$Officevibe (Unified Plan)$q$, $q$$5/user/month$q$, $q$Annual (or $6.25/user/month billed monthly)$q$, NULL, $q$["10-user minimum","Recurring pulse surveys","eNPS tracking","Anonymous feedback","Good Vibes peer recognition","AI-powered reporting and recommended actions"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Officevibe is built around continuous listening rather than a once-a-year engagement survey: short pulse surveys go out on a recurring basis, and results feed a running employee Net Promoter Score (eNPS) that managers can track over time.$q$, $q$Originally launched in 2013 by Montreal-based GSoft, the product has been part of Workleap (GSoft's 2023 rebrand) since then, sitting alongside Workleap's broader performance-management and skills tools as the company's dedicated engagement and pulse-survey product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Employees can submit anonymous feedback at any time, not just during a survey cycle, and managers get AI-generated highlights and suggested actions summarizing what the data is showing without needing to manually dig through raw responses.$q$, $q$'Good Vibes,' Officevibe's peer recognition feature, lets team members send public appreciation cards, while integrations with Slack, Microsoft Teams, and HRIS platforms keep survey participation and employee data in sync with the tools teams already use daily.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a31391fe-79aa-479e-ad05-f7def34d36ee', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Officevibe uses a single, simplified pricing tier as of 2024: $5 per user per month billed annually, or $6.25 per user per month billed monthly, with a 10-user minimum, replacing the previous Essential and Pro tiered structure.$q$, $q$This is separate from Workleap's broader HR platform pricing (Standard at $4,999/year and Pro at $11,999/year), which bundles performance management and compensation planning alongside engagement for organizations wanting a fuller HR suite.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Uptime monitoring$q$, $q$Checks site availability and alerts the team the moment a site or server goes down.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$SSL certificate monitoring$q$, $q$Tracks SSL certificate validity and warns before certificates expire or misconfigure.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Broken link and mixed-content checking$q$, $q$Scans sites for broken links and mixed-content issues that can hurt SEO and user trust.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Performance and Lighthouse audits$q$, $q$Runs Lighthouse-based performance checks to catch page-speed regressions over time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$DNS and domain-expiration monitoring$q$, $q$Watches DNS records for unexpected changes and alerts before domain registrations expire.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Scheduled task (cron) monitoring$q$, $q$Confirms that scheduled jobs and cron tasks actually run on time, not just that the server is up.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Public status pages$q$, $q$Publishes a branded status page that subscribers can follow for incident and uptime updates.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Every plan includes the full feature set, no functionality is gated behind higher tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Combines uptime, SSL, performance, DNS, and cron monitoring in one dashboard instead of several tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Built and actively maintained by two well-known developers in the Laravel and PHP community$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Transparent, predictable pricing based purely on number of sites monitored$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$10-day free trial with no credit card required, plus a 30-day money-back guarantee$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Pricing is per site or server, so monitoring many small sites can get expensive compared to unlimited-site competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Smaller company than large monitoring vendors, so integration breadth may be narrower$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$No free tier, unlike some competitors offering a limited always-free plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Primarily English-language interface and support$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Focused on website and infrastructure monitoring rather than full application performance monitoring (APM) depth$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Who built Oh Dear?$q$, $q$Oh Dear was founded in 2018 by Freek Van der Herten, a Belgian developer and agency owner, and Mattias Geniar, a sysadmin at the Belgian hosting company Nucleus.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$How much does Oh Dear cost?$q$, $q$Plans start at €15/month for 2 sites (Solo) and scale up based on the number of sites or servers monitored, up to €399/month for 200 sites, with custom Enterprise pricing above that.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Does Oh Dear monitor SSL certificates?$q$, $q$Yes, SSL certificate expiration and configuration monitoring is included on every plan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Can Oh Dear monitor cron jobs and scheduled tasks?$q$, $q$Yes, scheduled task (cron) monitoring is included on every plan, confirming jobs actually run on time.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Is there a free trial?$q$, $q$Yes, Oh Dear offers a 10-day free trial with no credit card required, along with a 30-day money-back guarantee.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Does Oh Dear offer status pages?$q$, $q$Yes, public status pages are included on every plan, letting subscribers follow uptime and incident updates.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$What's the difference between Oh Dear's pricing tiers?$q$, $q$All tiers include the same full feature set; the only difference between plans is the number of sites or servers you can monitor, which increases with each tier.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Freelance developer client monitoring$q$, $q$Freelancers monitor uptime, SSL, and performance across several client sites from one dashboard on the Freelance plan.$q$, $q$Freelance developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Agency-wide site health monitoring$q$, $q$Digital agencies use Oh Dear's Agency and Portfolio tiers to track uptime, broken links, and performance across dozens of client websites.$q$, $q$Digital agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$SaaS infrastructure and cron monitoring$q$, $q$SaaS teams monitor application uptime alongside scheduled background jobs to catch failures that a simple uptime check would miss.$q$, $q$SaaS engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Solo$q$, $q$€15/month$q$, $q$Monthly (2 months free annually)$q$, NULL, $q$["2 sites/servers","Full feature set included","10-day free trial"]$q$::jsonb, 0);
