INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Scale$q$, $q$€399/month$q$, $q$Monthly (2 months free annually)$q$, NULL, $q$["200 sites/servers","Full feature set included"]$q$::jsonb, 7);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["200+ sites/servers","Dedicated support","Custom contract terms"]$q$::jsonb, 8);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Oh Dear was built to solve a problem its two founders kept running into from opposite sides: Freek Van der Herten, a developer, worried about whether a site's application layer and content were working correctly, while Mattias Geniar, a sysadmin, worried about servers, DNS, and infrastructure staying up. Oh Dear combines both perspectives into one monitoring dashboard.$q$, $q$Rather than being a single-purpose uptime pinger, it bundles website and infrastructure checks that are normally split across several tools, uptime, SSL, performance, broken links, DNS, and scheduled tasks, into one product with one price per site.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Every Oh Dear plan includes the full feature set: uptime monitoring, SSL certificate expiration alerts, broken-link scanning, Lighthouse-based performance audits, DNS record and domain-expiration monitoring, scheduled task (cron) monitoring, ping and TCP port checks, and public status pages.$q$, $q$Because there are no feature-gated tiers, single sign-on, two-factor authentication, unlimited users, and status pages are available even on the entry-level Solo plan; only the number of monitored sites or servers changes as you move up in price.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7f675195-8d9d-4857-a42d-0da0b4ca4707', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Oh Dear's pricing scales purely by the number of sites or servers monitored rather than by feature access, starting at €15/month for 2 sites (Solo) and rising through several tiers up to €399/month for 200 sites (Scale), with custom Enterprise pricing above that.$q$, $q$Annual billing includes two months free compared to paying monthly, and new users get a 10-day free trial with no credit card required, plus a 30-day money-back guarantee.$q$]::text[], 2);
